abstract interface class CacheInterface {
  Future<void> initialize();

  Future<void> delete();

  Future<void> evictAll();

  Future<dynamic> urls();

  Future<bool> hasNext();

  Future<String> next();

  Future<void> remove();

  Future<int> writeAbortCount();

  Future<int> writeSuccessCount();

  Future<int> size();

  /// Max size of the cache (in bytes).
  Future<int> maxSize();

  Future<void> flush();

  Future<void> close();

  Future<File> directory();

  Future<void> trackResponse(CacheStrategy cacheStrategy);

  Future<void> trackConditionalCacheHit();

  Future<int> networkCount();

  Future<int> hitCount();

  Future<int> requestCount();

  Future<void> close();

  Future<void> abort();

  Future<Sink> body();

  Future<void> writeTo(dynamic editor);

  Future<bool> matches(Request request, Response response);

  Future<Response> response(dynamic snapshot);

  Future<void> close();

  Future<MediaType?> contentType();

  Future<int> contentLength();

  Future<BufferedSource> source();
}

